import React, { useState, useEffect, useMemo } from "react";
import SummaryCard from "../../components/SummaryCard.js";
import CommonInstructions from "../../components/CommonInstructions.js";
import MessageModal from "../../components/MessageModal.js";
import UserTable from "./UserMgmt/UserTable.js";
import ChangePasswordModal from "./UserMgmt/ChangePasswordModal.js";
import ChangeRoleModal from "./UserMgmt/ChangeRoleModal.js";
import SchemeMastersForm from "./Scheme/SchemeMastersForm";
import SchemeMastersTable from "./Scheme/SchemeMastersTable";
import axiosApi from "../../utils/axiosApi.js";
import * as bootstrap from "bootstrap";

const SchemeMasterInstructions = [
      "Enter master data for scheme related modules",
      "All fields marked * are mandatory and must be completed before saving.",
      "Review all information carefully before clicking Save or Update.",
      "All updates require confirmation before saving.",
      "Changes take effect immediately after successful update."
];  

const cards = [
   { title: "Scheme Type",count: 0,  bgColor: "#eff6ff", iconColor: "#1d4ed8", icon: "fa fa-list-alt" },
   { title: "Subsidy Type",count: 0 ,  bgColor: "#fef2f2", iconColor: "#dc2626", icon: "fa fa-list-alt" },
   { title: "Scheme Category",count: 0,  bgColor: "#fffbeb", iconColor: "#d97706", icon: "fa fa-list-alt" },   
   { title: "Scheme Sub-Category",count: 0,  bgColor: "#f0fdf4", iconColor: "#16a34a", icon: "fa fa-list-alt" },
   { title: "Vendors",count: 0,  bgColor: "rgb(247 247 247)", iconColor: "rgb(100 97 94)", icon: "fa fa-user" },   
   ];

const MODULES = {
   schemeType: {
      title: "Scheme Type",
      formTitle: "Add Scheme Type",
      listTitle: "Scheme Type List",
      listSubTitle: "scheme types",
      color: "#1d4ed8",
      bg: "#eff6ff",
      icon: "fa fa-layer-group",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-schemetype",
      fields: [
      { label: "Scheme Type",name:"scheme_type_name", type: "text", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Scheme Type(Local)",name:"scheme_type_name_local", type: "text", required: false, placeholder: "Scheme Type(Local)" },
    ],
   },
   subsidyType: {
      title: "Subsidy Type",
      formTitle: "Add Subsidy Type",
      listTitle: "Subsidy Type List",
      listSubTitle: "subsidy types",
      color: "#dc2626",
      bg: "#fef2f2",
      icon: "fa fa-money",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-subsidytype",
      fields: [
      { label: "Subsidy Type", name:"subsidy_type_name", type: "text", required: true, placeholder: "e.g. percentage" },
      { label: "Subsidy Type(Local)",name:"subsidy_type_name_local", type: "text", required: false, placeholder: "Subsidy Type(Local)" },
    ],
   },
   category: {
      title: "Scheme Category",
      formTitle: "Add Scheme Category",
      listSubTitle: "scheme category",
      listTitle: "Scheme Category List",
      color: "#d97706",
      bg: "#fffbeb",
      icon: "fa fa-folder",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-category",
      fields: [
      { label: "Category", name:"category_name", type: "text", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Category(Local)", name:"category_name_local", type: "text", required: false, placeholder: "Scheme Type(Local)" },
    ],
   },
   subCategory: {
      title: "Scheme Sub-Category",
      formTitle: "Add Scheme Sub-Category",
      listTitle: "Scheme Sub-Category List",
      listSubTitle: "scheme sub-category",
      color: "#16a34a",
      bg: "#f0fdf4",
      icon: "fa fa-sitemap",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-subcategory",
      fields: [
      { label: "Category", name:"category_id", type: "select",optionKey: "category", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Sub-Category", name:"subcategory_name", type: "text", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Sub-Category(Local)", name:"subcategory_name_local", type: "text", required: false, placeholder: "Scheme Type(Local)" },
      { label: "Min area required", name:"min_area_req_yn", type: "select",options: [{ value: "Y", label: "Yes" },{ value: "N", label: "No" }], 
               required: true, placeholder: "e.g. Central Scheme" },
    ],
   },
   technology: {
      title: "Scheme Technology",
      formTitle: "Add Scheme Technology",
      listTitle: "Scheme Technology List",
      listSubTitle: "technologies",
      color: "#0891b2",
      bg: "#ecfeff",
      icon: "fa fa-cogs",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-technology",
      fields: [
      { label: "Sub-Category", name:"subcategory_id", type: "select", optionKey: "subcategory",required: true, placeholder: "e.g. Central Scheme" },
      { label: "Technology", name:"technology_name", type: "text", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Technology(Local)", name:"technology_name_local", type: "text", required: false, placeholder: "Scheme Type(Local)" },
    ],
   },
   documents: {
      title: "Document",
      formTitle: "Add Documents",
      listTitle: "Documents List",
      listSubTitle: "documents",
      color: "#dc2626",
      bg: "#fef2f2",
      icon: "fa fa-file",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-documenttype",
      fields: [
      { label: "Document Type", name:"document_type_id",optionKey: "documenttypes", type: "select", required: true },
      { label: "Document", name:"document_name", type: "text", required: true, placeholder: "e.g. Aadhar Card" },
      { label: "Document(Local)", name:"document_name_local", type: "text", required: false, placeholder: "Document(Local)" },
    ],
   },
   vendor: {
      title: "Vendor",
      formTitle: "Add Vendor",
      listTitle: "Vendor List",
      listSubTitle: "vendors",
      color: "#44403c",
      bg: "#f5f5f4",
      icon: "fa fa-building",
      saveApi: "/scheme/updateschemetype",
      listApi: "/scheme/get-schemetype",
      fields: [
      { label: "Vendor Name", name:"vendor_name", type: "text", required: true, placeholder: "e.g. ABC Traders" },
      { label: "Vendor Name (Local)", name:"vendor_name_local", type: "text", required: true, placeholder: "e.g. ABC Traders" },
      { label: "Contact Person", name:"contact_person", type: "text", placeholder: "e.g. Ramesh Kumar" },
      { label: "Mobile No.", name:"contact_no_1", type: "text", placeholder: "e.g. 9876543210" },
      { label: "Mobile No. 2", name:"contact_no_2", type: "text", placeholder: "e.g. 9876543210" },
      { label: "Email", name:"email", type: "email", placeholder: "e.g. vendor@example.com" },
      { label: "Address", name:"office_address", type: "textarea", placeholder: "Optional address" },
      { label: "GST No.", name:"gst_no", type: "text", placeholder: "Optional address" },
    ],
   }
};

function SchemeMasterEntry({ setModuleName }) {
   const [selectedModule, setSelectedModule] = useState("schemeType");
   const activeModule = MODULES[selectedModule];
   const [dropdowns, setDropdowns] = useState({ category: [], documenttypes: [], subcategory: [] });
   const [formData, setFormData] = useState({scheme_type: "",scheme_type_local: ""});

   const [messageModal, setMessageModal] = useState({ show: false, title: "", message: "", type: "success",isConfirmation: false, onConfirm: null,});
   
   const showMessage = ( title, message, type = "success", isConfirmation = false, onConfirm = null ) => {
                           setMessageModal({ show: true, title, message, type,isConfirmation, onConfirm });};
  
   useEffect(() => {
      const loadData = async () => {
         await Promise.all([
            fetchData("/scheme/get-documenttype", "documenttypes"),
            fetchData("/scheme/get-category", "category")
         ]);
      };
      setModuleName("User Management");
      loadData();
   }, []);

   useEffect(() => {
      const initialData = {
         status: "A",   // Active
         action: "S"    // Save
      };
      activeModule.fields.forEach(field => {
         initialData[field.name] = "";
      });

      setFormData(initialData);
   }, [activeModule]);
   
   const dropdownApis = {
      category: "/scheme/get-category",
      documenttypes: "/scheme/get-documenttype",
      subcategory: "/scheme/get-subcategory"
   };
   const fetchData = async (url, key) => {
      try {
         const response = await axiosApi.get(url);

         setDropdowns(prev => ({
               ...prev,
               [key]: response.data
         }));
      } catch (err) {
         console.error(err);
      }
   };

   const handleSaveConfirmation = (e) => {
      if (e) e.preventDefault();
      // if (!validateForm()) {
      //    return;
      // }
      //const message = employee.action === "U" ? "Are you sure you want to update details?" : "Are you sure you want to save details?"; 
      const message = "Are you sure you want to save details?"; 
      showMessage("Confirmation", message, "warning", true, () => handleSubmit());
   };
   const handleSubmit = async () => {
      try {
         const response = await axiosApi.post(
               activeModule.saveApi,
               formData
         );
         showMessage("Success", response.data.message, "success");
         handleReset();
      } catch (err) {
         const message = err.response?.data?.message || err.response?.data?.error || err.message || "Error while saving";
         showMessage("Error", message, "error");
      }
   };
   const handleChange = (e) => {
      setFormData({
         ...formData,
         [e.target.name]: e.target.value
      });

   };
   const handleReset = () => {
      const initialData = {};
      activeModule.fields.forEach(field => {
         initialData[field.name] = "";
      });

      setFormData(initialData);
   };

  return (
      <div className="container-fluid content-inner mt-n5 px-3 py-0">
         <div className="row g-3 py-3">
            <div className="col-xl-2 col-lg-4">
               {cards.map((card, index) => (
                  <SummaryCard key={index} {...card} />
                  ))}

               <CommonInstructions title="Instructions" instructions={SchemeMasterInstructions} /> 
            </div>
            <div className="col-xl-10 col-lg-4">
               <div className="row">
                  <div className="col-xl-3 col-lg-4">
                     <div className="card">
                        <div className="card-body" style={{minHeight:"650px"}}>
                           <p>Click on the below button to start entry</p>
                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "schemeType"? "btn-primary": "btn-outline-primary"}`}
                           onClick={() => setSelectedModule("schemeType")}>Add Scheme Type</button>

                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "subsidyType"? "btn-danger": "btn-outline-danger"}`}
                           onClick={() => setSelectedModule("subsidyType")}>Add Subsidy Type</button>

                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "category"? "btn-warning": "btn-outline-warning"}`}
                           onClick={() => setSelectedModule("category")}>Add Scheme Category</button>

                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "subCategory"? "btn-success": "btn-outline-success"}`}
                           onClick={() => setSelectedModule("subCategory")}>Add Scheme Sub-Category</button>

                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "technology"? "btn-info": "btn-outline-info"}`}
                           onClick={() => setSelectedModule("technology")}>Add Scheme Technology</button>

                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "documents"? "btn-danger": "btn-outline-danger"}`}
                           onClick={() => setSelectedModule("documents")}>Add Documents</button>
                           
                           <button type="button" className={`btn w-100 mb-3 ${ selectedModule === "vendor"? "btn-dark": "btn-outline-dark"}`}
                           onClick={() => setSelectedModule("vendor")}>Add Vendors</button>
                        </div>
                     </div>
                  </div>
                  <div className="col-xl-4 col-lg-4">
                        <SchemeMastersTable  module={activeModule}/>
                  </div>
                  <div className="col-xl-5 col-lg-4">
                        <SchemeMastersForm
                           module={activeModule}
                           formData={formData}
                           handleChange={handleChange}
                           handleSaveConfirmation={handleSaveConfirmation}
                           handleReset={handleReset}
                           dropdowns={dropdowns}
                        />
                  </div>
                  <MessageModal show={messageModal.show} title={messageModal.title} message={messageModal.message} type={messageModal.type}
                     isConfirmation={messageModal.isConfirmation} onConfirm={messageModal.onConfirm} 
                     onClose={() => setMessageModal((prev) => ({ ...prev, show: false, })) } />
               </div>
            </div>
         </div>
      </div>
 );
}
export default SchemeMasterEntry;
